const current = $('HTTP Request - Semaine courante').first().json.rows || [];
const previous = $('HTTP Request - Semaine précédente').first().json.rows || [];

// Crée un map semaine précédente par query
const prevMap = {};
for (const row of previous) {
  prevMap[row.keys[0]] = row;
}

// Calcule les variations
const enriched = current.map(row => {
  const query = row.keys[0];
  const page  = row.keys[1];
  const prev  = prevMap[query];

  const deltaClics    = prev ? row.clicks - prev.clicks : null;
  const deltaPosition = prev ? prev.position - row.position : null; // positif = amélioration

  return {
    query,
    page,
    clics:         row.clicks,
    impressions:   row.impressions,
    ctr:           (row.ctr * 100).toFixed(1) + '%',
    position:      row.position.toFixed(1),
    deltaClics,
    deltaPosition: deltaPosition ? deltaPosition.toFixed(1) : 'nouveau',
    tendance:      deltaPosition > 0 ? '📈' : deltaPosition < 0 ? '📉' : '➡️'
  };
});

// Top 5 progressions / régressions
const progressions = [...enriched]
  .filter(r => r.deltaPosition !== 'nouveau')
  .sort((a, b) => b.deltaPosition - a.deltaPosition)
  .slice(0, 5);

const regressions = [...enriched]
  .filter(r => r.deltaPosition !== 'nouveau')
  .sort((a, b) => a.deltaPosition - b.deltaPosition)
  .slice(0, 5);

// Totaux globaux
const totalClics       = enriched.reduce((s, r) => s + r.clics, 0);
const totalImpressions = enriched.reduce((s, r) => s + r.impressions, 0);
const totalClicsPrev   = previous.reduce((s, r) => s + r.clicks, 0);
const deltaTotal       = totalClics - totalClicsPrev;

return [{
  json: {
    semaine:    $today.minus({days: 7}).toFormat('dd/MM') + ' → ' + $today.minus({days: 1}).toFormat('dd/MM/yyyy'),
    totalClics,
    totalImpressions,
    deltaTotal,
    top25:      enriched,
    progressions,
    regressions
  }
}];

const d = $input.first().json;

const fleche = d.deltaTotal >= 0 ? '▲' : '▼';
const signe  = d.deltaTotal >= 0 ? '+' : '';

let lignesTop = d.top25.slice(0, 10).map(r =>
  `${r.tendance} <b>${r.query}</b>\n` +
  `   ${r.clics} clics · pos. ${r.position} · CTR ${r.ctr}`
).join('\n\n');

let lignesHausse = d.progressions.map(r =>
  `📈 <b>${r.query}</b> : +${r.deltaPosition} pos. (→ ${r.position})`
).join('\n');

let lignesBaisse = d.regressions.map(r =>
  `📉 <b>${r.query}</b> : ${r.deltaPosition} pos. (→ ${r.position})`
).join('\n');

const message = 
`📊 <b>Rapport SEO — ${d.semaine}</b>

<b>Vue d'ensemble</b>
🖱 Clics totaux : ${d.totalClics} (${fleche} ${signe}${d.deltaTotal} vs semaine préc.)
👁 Impressions  : ${d.totalImpressions}

<b>Top 10 requêtes</b>
${lignesTop}

<b>Meilleures progressions</b>
${lignesHausse}

<b>Points de vigilance</b>
${lignesBaisse}`;

return [{ json: { message } }];
